#include <stdio.h>

void format_print(const char* text) {
    if (text != NULL) {
        printf("Length: %lu\n", (unsigned long)strlen(text));
    } else {
        printf("Text was empty\n");
    }
}

examples.toCode:
func formatPrint(text: String?) {
    // The compiler prevents accessing text.length directly without safe validation
    if (text != null) {
        println("Length: ${text.length}")
    } else {
        println("Text was empty")
    }
}

